import React from 'react';
import Header from '../components/header/header';
import Footer from '../components/Footer/Footer';
import { ResolvedContentProvider } from '../ppm/util/ResolvedContentContext';

interface PostDetailProps {
  pageContext: {
    item: {
      title: string;
      subtitle?: string;
      body: string;
      image?: string;
      date?: string;
      category?: string;
    };
  };
}

const PostDetail: React.FC<PostDetailProps> = ({ pageContext }) => {
  const { item } = pageContext;

  // Function to process body content with ImageKit CDN
  const processContent = (html: string) => {
    if (!html) return '';
    
    // 1. Replace bpkq domain with ImageKit CDN for better performance and to ensure visibility
    let processed = html.replace(
      /http:\/\/bodephatquoc\.org\/wp-content\/uploads\//g, 
      'https://ik.imagekit.io/dloitl7fd8/wp-content/uploads/'
    );

    // 2. Wrap Foogallery style links (common in migrated data) to ensure they show up as a grid
    // Look for clusters of image links and wrap them in foogallery-container
    processed = processed.replace(
      /<a([^>]+)href=["']([^"']+\.(?:jpg|jpeg|png|gif|webp|bmp))["']([^>]*)>\s*<img[^>]+>\s*<\/a>/gi, 
      '<a$1href="$2"$3><img src="$2" loading="lazy" alt="Gallery Image" /></a>'
    );

    // 3. Ensure any direct <img> tags also use the CDN (if not already handled)
    processed = processed.replace(
      /src=["']http:\/\/bodephatquoc\.org\/wp-content\/uploads\/([^"']+)["']/g,
      'src="https://ik.imagekit.io/dloitl7fd8/wp-content/uploads/$1"'
    );

    return processed;
  };

  const processedBody = processContent(item.body);

  return (
    <ResolvedContentProvider>
      <div className="post-detail-wrapper">
        <Header showHero={false} />
        
        {/* Placeholder for header spacing since it's fixed */}
        <div className="header-padding" />

        <main className="post-detail-main">
          <article className="post-article">
            <header className="post-header">
              {item.category && (
                <span className="post-category">
                  {item.category}
                </span>
              )}
              <h1 className="post-title">
                {item.title}
              </h1>
              <div className="post-header-underline" />
              {item.date && (
                <p className="post-date">
                  {item.date}
                </p>
              )}
            </header>

            {!processedBody && item.image && (
              <div className="post-image-container">
                <img 
                  src={item.image} 
                  alt={item.title} 
                  className="post-main-image"
                />
              </div>
            )}

            <div className={`post-content-card ${!processedBody ? 'empty-body' : ''}`}>
              {processedBody ? (
                <div 
                  className="post-body-content"
                  dangerouslySetInnerHTML={{ 
                    __html: processedBody
                  }} 
                />
              ) : (
                <div className="post-body-placeholder">
                  {item.image && processedBody === '' ? (
                    <p style={{ textAlign: 'center', color: '#888' }}>
                      Nội dung này hiện đang được cập nhật. Quý khách vui lòng quay lại sau.
                    </p>
                  ) : (
                    <div className="post-body-content" dangerouslySetInnerHTML={{ __html: item.body }} />
                  )}
                </div>
              )}
            </div>
          </article>
        </main>

        <Footer />
      </div>
      
      <style dangerouslySetInnerHTML={{ __html: `
        :root {
          --color-ivory: #f9f7f2;
          --color-off-white: #f5f3ee;
          --color-gold: #E6B422;
          --color-charcoal: #2c3e36;
          --color-dark-green: #1a2a24;
          --font-serif: 'Playfair Display', Georgia, serif;
          --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
        }

        .post-detail-wrapper {
          min-height: 100vh;
          background-color: var(--color-off-white);
          color: var(--color-charcoal);
          font-family: var(--font-sans);
        }
        
        .header-padding {
          height: 140px; /* Space for fixed header */
        }

        .post-detail-main {
          max-width: 1000px;
          margin: 0 auto;
          padding: 40px 24px 80px;
        }

        .post-header {
          text-align: center;
          margin-bottom: 60px;
        }

        .post-category {
          display: inline-block;
          padding: 4px 16px;
          background-color: transparent;
          color: var(--color-gold);
          border-bottom: 1px solid var(--color-gold);
          font-size: 14px;
          font-weight: 500;
          text-transform: uppercase;
          letter-spacing: 1.5px;
          margin-bottom: 24px;
        }

        .post-title {
          font-family: var(--font-serif);
          font-size: 48px;
          font-weight: 600;
          color: var(--color-dark-green);
          line-height: 1.2;
          margin: 0 auto 24px;
          max-width: 850px;
        }

        .post-header-underline {
          width: 80px;
          height: 4px;
          background-color: var(--color-gold);
          margin: 0 auto 24px;
        }

        .post-date {
          color: #888;
          font-size: 15px;
          font-weight: 300;
          letter-spacing: 0.5px;
        }

        .post-image-container {
          width: 100%;
          border-radius: 12px;
          overflow: hidden;
          margin-bottom: 60px;
          box-shadow: 0 20px 40px rgba(0, 0, 0, 0.08);
          border: 1px solid rgba(0, 0, 0, 0.05);
        }

        .post-main-image {
          width: 100%;
          height: auto;
          display: block;
        }

        .post-content-card {
          background-color: #ffffff;
          padding: 60px;
          border-radius: 24px;
          box-shadow: 0 10px 30px rgba(0, 0, 0, 0.03);
          border: 1px solid rgba(0, 0, 0, 0.05);
        }

        .post-body-content {
          font-size: 19px;
          line-height: 1.8;
          color: var(--color-charcoal);
        }

        .post-body-content p { 
          margin-bottom: 28px; 
          text-align: justify;
        }

        .post-body-content h2, .post-body-content h3 { 
          font-family: var(--font-serif);
          color: var(--color-dark-green);
          margin-top: 50px; 
          margin-bottom: 24px; 
          font-weight: 600;
        }

        .post-body-content h2 { font-size: 32px; }
        .post-body-content h3 { font-size: 26px; }

        .post-body-content img { 
          max-width: 100%; 
          height: auto; 
          border-radius: 12px; 
          margin: 40px auto; 
          display: block;
          box-shadow: 0 10px 25px rgba(0, 0, 0, 0.05);
        }

        .post-body-content a {
          color: var(--color-gold);
          text-decoration: none;
          border-bottom: 1px solid rgba(230, 180, 34, 0.3);
          transition: border-bottom 0.2s;
        }

        .post-body-content a:hover {
          border-bottom: 1px solid var(--color-gold);
        }

        .post-body-content blockquote {
          margin: 40px 0;
          padding: 20px 40px;
          border-left: 5px solid var(--color-gold);
          background-color: var(--color-ivory);
          font-style: italic;
          color: #555;
          border-radius: 0 12px 12px 0;
        }

        /* Gallery/FooGallery Styling for Migrated Content */
        .foogallery-container {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
          gap: 16px;
          margin: 40px 0;
          padding: 20px;
          background-color: var(--color-ivory);
          border-radius: 16px;
        }

        .foogallery-container a {
          border-bottom: none !important;
          transition: transform 0.3s ease;
          display: block;
          overflow: hidden;
          border-radius: 8px;
        }

        .foogallery-container a:hover {
          transform: scale(1.05);
          box-shadow: 0 10px 20px rgba(0,0,0,0.1);
          z-index: 10;
        }

        .foogallery-container img {
          width: 100% !important;
          height: 180px !important;
          object-fit: cover !important;
          margin: 0 !important;
          border-radius: 8px !important;
        }

        /* Clean up injected DB styles */
        .post-body-content div, .post-body-content span, .post-body-content p {
          max-width: 100%;
        }
        
        .clearfix::after {
          content: "";
          clear: both;
          display: table;
        }

        @media (max-width: 768px) {
          .header-padding { height: 100px; }
          .post-title { font-size: 32px; }
          .post-content-card { padding: 30px 20px; }
          .post-body-content { font-size: 17px; }
          .post-detail-main { padding-top: 20px; }
        }
      `}} />
    </ResolvedContentProvider>
  );
};

export default PostDetail;
